function Get-OrCreateResourceGroup {
    param(
        [string]$Name,
        [string]$Location,
        [hashtable]$Tags = @{}
    )
    $rg = Get-AzResourceGroup -Name $Name -ErrorAction SilentlyContinue
    if ($rg) {
        Write-Verbose "Resource group '$Name' already exists in $($rg.Location)"
        return $rg
    }
    Write-Verbose "Creating resource group '$Name' in $Location"
    return New-AzResourceGroup -Name $Name -Location $Location -Tag $Tags
}

function Get-AzVMStatus {
    param([string]$ResourceGroupName, [string]$VMName)
    $vm = Get-AzVM -ResourceGroupName $ResourceGroupName -Name $VMName -Status -ErrorAction Stop
    return ($vm.Statuses | Where-Object Code -like "PowerState/*").DisplayStatus
}

# Usage
$rg     = Get-OrCreateResourceGroup -Name $ResourceGroupName -Location $Location -Tags @{Env="Dev"}
$status = Get-AzVMStatus -ResourceGroupName $ResourceGroupName -VMName $VMName
Write-Host "VM status: $status"

function Invoke-AzOperation {
    param([scriptblock]$Operation, [string]$Description, [int]$MaxRetries = 3)
    $attempt = 0
    $delay   = 2
    while ($attempt -lt $MaxRetries) {
        try {
            return & $Operation
        } catch [Microsoft.Azure.Commands.Common.Exceptions.AzPSException] {
            # Az-specific exception: resource not found, policy denial, etc.
            if ($_.Exception.Message -like "*ResourceNotFound*") {
                Write-Error "Resource not found during: $Description"
                throw
            }
            Write-Warning "Attempt $($attempt+1) failed for '$Description': $($_.Exception.Message)"
        } catch {
            # Unexpected error — do not retry
            Write-Error "Unexpected error during '$Description': $_"
            throw
        }
        $attempt++
        if ($attempt -lt $MaxRetries) {
            Write-Verbose "Retrying in ${delay}s..."
            Start-Sleep -Seconds $delay
            $delay *= 2
        }
    }
    throw "All $MaxRetries attempts failed for: $Description"
}

# Usage:
$vm = Invoke-AzOperation -Description "Get VM" -Operation {
    Get-AzVM -ResourceGroupName $ResourceGroupName -Name $VMName -ErrorAction Stop
}

function Invoke-VMInventory {
    param([string[]]$ResourceGroups)

    foreach ($rg in $ResourceGroups) {
        $vms = Get-AzVM -ResourceGroupName $rg -Status -ErrorAction SilentlyContinue
        foreach ($vm in $vms) {
            $powerState = ($vm.Statuses | Where-Object Code -like "PowerState/*").DisplayStatus
            [PSCustomObject]@{
                ResourceGroup = $rg
                VMName        = $vm.Name
                Location      = $vm.Location
                Size          = $vm.HardwareProfile.VmSize
                PowerState    = $powerState
                OSDisk        = $vm.StorageProfile.OsDisk.DiskSizeGB
                Tags          = ($vm.Tags | ConvertTo-Json -Compress)
            }
        }
    }
}

# Callers compose naturally:
$allRGs = (Get-AzResourceGroup).ResourceGroupName
Invoke-VMInventory -ResourceGroups $allRGs |
    Where-Object PowerState -eq "VM deallocated" |
    Select-Object VMName, ResourceGroup, Size |
    Export-Csv -Path deallocated-vms.csv -NoTypeInformation

