function Invoke-IdempotentResourceGroup {
    [CmdletBinding(SupportsShouldProcess)]
    param(
        [Parameter(Mandatory)][string]$Name,
        [Parameter(Mandatory)][string]$Location,
        [hashtable]$Tags = @{}
    )
    if ($PSCmdlet.ShouldProcess($Name, "Create resource group")) {
        $existing = Get-AzResourceGroup -Name $Name -ErrorAction SilentlyContinue
        if (-not $existing) {
            New-AzResourceGroup -Name $Name -Location $Location -Tag $Tags
        } else {
            $existing
        }
    }
}

function Get-AzVMsByTag {
    param([hashtable]$Tag)
    Get-AzResource -Tag $Tag |
        Where-Object ResourceType -eq "Microsoft.Compute/virtualMachines"
}

Export-ModuleMember -Function Invoke-IdempotentResourceGroup, Get-AzVMsByTag

# File: AzHelpers.Tests.ps1
#Requires -Modules @{ModuleName='Pester'; ModuleVersion='5.0.0'}

BeforeAll {
    Import-Module ".\AzHelpers.psm1" -Force
}

Describe "Invoke-IdempotentResourceGroup" {
    Context "When the resource group already exists" {
        It "returns the existing group without creating a new one" {
            $fakeRG = [PSCustomObject]@{ResourceGroupName="myRG"; Location="eastus"}
            # Mock the Az cmdlet to return a fake object
            Mock Get-AzResourceGroup { return $fakeRG }
            Mock New-AzResourceGroup { }

            $result = Invoke-IdempotentResourceGroup -Name "myRG" -Location "eastus"

            $result.ResourceGroupName | Should -Be "myRG"
            # Assert New-AzResourceGroup was never called
            Should -Invoke New-AzResourceGroup -Times 0
        }
    }

    Context "When the resource group does not exist" {
        It "creates and returns a new resource group" {
            Mock Get-AzResourceGroup { return $null }
            Mock New-AzResourceGroup { return [PSCustomObject]@{ResourceGroupName="newRG"; Location="westus2"} }

            $result = Invoke-IdempotentResourceGroup -Name "newRG" -Location "westus2"

            $result.ResourceGroupName | Should -Be "newRG"
            Should -Invoke New-AzResourceGroup -Times 1
        }
    }
}

#!/usr/bin/env pwsh
#Requires -Version 7.0
#Requires -Modules @{ModuleName='Az.Accounts';ModuleVersion='2.0.0'},
                   @{ModuleName='Az.Storage';ModuleVersion='5.0.0'},
                   @{ModuleName='Az.KeyVault';ModuleVersion='4.0.0'}

param(
    [Parameter(Mandatory)][ValidateNotNullOrEmpty()][string]$ResourceGroupName,
    [Parameter(Mandatory)][ValidateNotNullOrEmpty()][string]$StorageAccountName,
    [ValidateSet("eastus","westus2","westeurope")][string]$Location = "eastus",
    [ValidateSet("Standard_LRS","Standard_GRS","Standard_ZRS")][string]$Sku = "Standard_LRS",
    [string]$KeyVaultName,
    [switch]$WhatIf
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"
Disable-AzContextAutosave -Scope Process | Out-Null
Connect-AzAccount -Identity | Out-Null

function Write-Log {
    param([string]$Level, [string]$Message)
    $ts = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ssZ")
    Write-Host "[$ts][$Level] $Message" -ForegroundColor ($Level -eq "ERROR" ? "Red" : "Cyan")
}

function Get-OrCreateStorageAccount {
    param([string]$Name, [string]$RG, [string]$Loc, [string]$SkuName)
    $sa = Get-AzStorageAccount -ResourceGroupName $RG -Name $Name -ErrorAction SilentlyContinue
    if ($sa) {
        Write-Log INFO "Storage account '$Name' exists, skipping creation."
        return $sa
    }
    Write-Log INFO "Creating storage account '$Name' in $RG ($Loc, $SkuName)..."
    return New-AzStorageAccount -ResourceGroupName $RG -Name $Name `
        -Location $Loc -SkuName $SkuName -Kind StorageV2 -EnableHttpsTrafficOnly $true
}

try {
    if ($WhatIf) {
        Write-Log INFO "[WHATIF] Would create storage account '$StorageAccountName' in '$ResourceGroupName'"
        exit 0
    }

    $sa = Get-OrCreateStorageAccount -Name $StorageAccountName `
        -RG $ResourceGroupName -Loc $Location -SkuName $Sku

    if ($KeyVaultName) {
        $connStr = (Get-AzStorageAccountKey -ResourceGroupName $ResourceGroupName `
            -Name $StorageAccountName)[0].Value
        $secVal  = ConvertTo-SecureString "DefaultEndpointsProtocol=https;AccountName=$StorageAccountName;AccountKey=$connStr;EndpointSuffix=core.windows.net" -AsPlainText -Force
        Set-AzKeyVaultSecret -VaultName $KeyVaultName -Name "$StorageAccountName-connstr" -SecretValue $secVal | Out-Null
        Write-Log INFO "Connection string stored in Key Vault '$KeyVaultName'."
    }

    [PSCustomObject]@{
        Status              = "ok"
        StorageAccountName  = $sa.StorageAccountName
        ResourceGroupName   = $sa.ResourceGroupName
        Location            = $sa.Location
        Sku                 = $sa.Sku.Name
        PrimaryBlobEndpoint = $sa.PrimaryEndpoints.Blob
    }
} catch {
    Write-Log ERROR "Script failed: $_"
    exit 1
}

# Wait for an async Az operation (-AsJob)
$job = Remove-AzResourceGroup -Name myTempRG -Force -AsJob
Write-Host "Deletion started as background job: $($job.Id)"

# Poll until complete
while ($job.State -in "NotStarted","Running") {
    Start-Sleep -Seconds 10
    Write-Host "Job state: $($job.State)"
}
if ($job.State -ne "Completed") {
    Write-Error "Deletion failed: $($job.Error)"
}

# Wait for multiple async deletions
$jobs = "rg1","rg2","rg3" | ForEach-Object {
    Remove-AzResourceGroup -Name $_ -Force -AsJob
}
$jobs | Wait-Job | Receive-Job

# Wait for a VM deployment to reach Running state
$deadline = (Get-Date).AddMinutes(15)
do {
    Start-Sleep -Seconds 30
    $status = (Get-AzVM -ResourceGroupName myRG -Name myVM -Status).Statuses |
        Where-Object Code -like "PowerState/*" | Select-Object -ExpandProperty DisplayStatus
    Write-Host "VM state: $status"
} until ($status -eq "VM running" -or (Get-Date) -gt $deadline)
if ((Get-Date) -gt $deadline) { Write-Error "Timeout waiting for VM to start" }

function Write-AuditLog {
    param(
        [string]$Action,
        [string]$Resource,
        [string]$Status,
        [string]$Detail = ""
    )
    $entry = [PSCustomObject]@{
        Timestamp = (Get-Date).ToString("o")
        RunId     = $env:GITHUB_RUN_ID ?? [System.Guid]::NewGuid().ToString()
        Action    = $Action
        Resource  = $Resource
        Status    = $Status
        Detail    = $Detail
        RunBy     = $env:GITHUB_ACTOR ?? $env:USERNAME ?? "unknown"
    }
    # Write to stdout as JSON (captured by CI log aggregators)
    $entry | ConvertTo-Json -Compress | Write-Host
    # Append to a local JSONL file for local runs
    if ($env:AUDIT_LOG_PATH) {
        $entry | ConvertTo-Json -Compress | Add-Content -Path $env:AUDIT_LOG_PATH
    }
}

# Usage throughout a script:
Write-AuditLog -Action "Create" -Resource "ResourceGroup/myRG" -Status "started"
try {
    New-AzResourceGroup -Name myRG -Location eastus
    Write-AuditLog -Action "Create" -Resource "ResourceGroup/myRG" -Status "succeeded"
} catch {
    Write-AuditLog -Action "Create" -Resource "ResourceGroup/myRG" `
        -Status "failed" -Detail $_.Exception.Message
    throw
}
